// Способ 1: цикл for
fun printAll(strings: Collection<String>) {
    for (str in strings) print("$str ")
}

// Способ 2: forEach
fun printAll(songs: Collection<String>) {
    songs.forEach { print("$it ") }
}

// Способ 3: итератор
fun printAll(songs: Collection<String>) {
    val iter = songs.iterator()
    while (iter.hasNext()) {
        print("${iter.next()} ")
    }
}

val songs = listOf("Creep", "Idioteque", "Street Spirit")
