fun main() {
    // Прямой порядок
    for (i in 1..4) print(i)       // 1234
    println()

    // Обратный порядок
    for (i in 4 downTo 1) print(i) // 4321
    println()

    // С шагом
    for (i in 1..8 step 2) print(i)       // 1357
    println()
    for (i in 8 downTo 1 step 2) print(i) // 8642
    println()

    // Исключая последний элемент
    for (i in 1 until 10) print(i) // 123456789 (без 10!)
}

class Version(val major: Int, val minor: Int) : Comparable<Version> {
    override fun compareTo(other: Version): Int {
        if (this.major != other.major) {
            return this.major - other.major
        }
        return this.minor - other.minor
    }
}

fun main() {
    val versionRange = Version(1, 11)..Version(1, 30)
    println(Version(0, 9) in versionRange)  // false
    println(Version(1, 20) in versionRange) // true
}

fun main() {
    // Прогрессия 1..10, step = 1
    for (i in 1..10) print(i) // 12345678910

    // Прогрессия 1..8, step = 2
    for (i in 1..8 step 2) print(i) // 1357

    // Обратная прогрессия
    for (i in 4 downTo 1) print(i) // 4321
}

fun main() {
    // Фильтрация чётных чисел
    println((1..10).filter { it % 2 == 0 })
    // [2, 4, 6, 8, 10]

    // Преобразование в список квадратов
    println((1..5).map { it * it })
    // [1, 4, 9, 16, 25]

    // Сумма элементов прогрессии
    println((1..100).sum())
    // 5050

    // Преобразование в список
    println((1..5 step 2).toList())
    // [1, 3, 5]
}
